import React from 'react';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';

const Dashboard = () => {
  return (
    <div style={{ fontFamily: 'sans-serif', color: '#334155' }}>
      <Navbar />
      <Sidebar />
      
      <main style={{ marginLeft: '260px', marginTop: '80px', padding: '20px' }}>
        <div style={{ backgroundColor: '#ffffff', padding: '30px', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
          <h1 style={{ color: '#0f172a', marginTop: 0 }}>📊 Panel de Control Principal</h1>
          <p style={{ fontSize: '1.1rem', color: '#64748b' }}>Bienvenido al Sistema de Gestión de Planillas de Cátedra.</p>
          <hr style={{ border: '0', height: '1px', backgroundColor: '#e2e8f0', margin: '20px 0' }} />
          
          <h3>Resumen Técnico de Entrega (Fase II):</h3>
          <ul style={{ lineHeight: '1.8' }}>
            <li><strong>Backend de Datos:</strong> Operando sobre Spring Boot y base de datos relacional MySQL.</li>
            <li><strong>Seguridad del Sistema:</strong> Filtros de Spring Security activos y validación por firmas de tokens <strong>JWT</strong>.</li>
            <li><strong>Lógica de Negocio:</strong> Cálculos de descuentos automáticos basados en la legislación de El Salvador (AFP 7.25% e ISSS 3%).</li>
            <li><strong>Escudo de Persistencia:</strong> Bloqueo nativo contra registros duplicados de empleados o planillas emitidas en el mismo periodo.</li>
          </ul>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
